SELECT id, examTypeId, examSubjectId, title, timeLimitMin, isActive, createdAt
FROM qbank_exam_paper

    AND examTypeId = #{typeId}
    AND examSubjectId = #{subjectId}
    AND isActive = #{isActive}

ORDER BY id

